INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (2, 100101, 0, 27, "トゥインクルウィッシュ", "ヒヨリ", 8, "A", "人助けが大好き！　前向き格闘娘", "東山奈央", "人助け、応援", "獣人族", 44, 16, 155, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (2, 100201, 0, 5, "トゥインクルウィッシュ", "ユイ", 4, "O", "戦闘のサポートが得意な、心優しい少女", "種田梨沙", "料理、人間観察", "ヒューマン", 47, 17, 158, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (2, 100301, 0, 12, "トゥインクルウィッシュ", "レイ", 1, "B", "クールで何事にも真っ直ぐな剣士", "早見沙織", "読書、乗馬、お茶", "魔族", 46, 18, 163, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (5, 100401, 0, 10, "リトルリリカル", "ミソギ", 8, "O", "探検好きのイタズラっ子", "諸星すみれ", "いたずら、探検", "ヒューマン", 27, 9, 128, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪");
