INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (7, 100601, 0, 22, "悪魔偽王国軍（ディアボロス）", "アカリ", 11, "O", "甘え上手なみんなの人気者", "浅倉杏美", "サックス", "魔族", 42, 13, 150, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (7, 100701, 0, 23, "悪魔偽王国軍（ディアボロス）", "ミヤコ", 1, "B", "プリン大好きゴースト娘", "雨宮天", "プリンを食べること", "魔族", 32, 14, 130, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (15, 100801, 0, 10, "ヴァイスフリューゲル　ランドソル支部", "ユキ", 10, "AB", "ボクは誰よりも美しい", "大空直美", "鏡で自分を見ること", "エルフ", 40, 14, 150, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (13, 100901, 0, 5, "トワイライトキャラバン", "アンナ", 7, "A", "前世を信じる中二病患者、「疾風の冥姫」", "髙野麻美", "小説執筆", "魔族", 45, 17, 159, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (10, 101001, 0, 22, "自警団（カォン）", "マホ", 9, "O", "マホマホ王国のプリンセス", "内田真礼", "空想、ぬいぐるみ集め", "獣人族", 42, 16, 155, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (3, 101101, 0, 25, "ラビリンス", "リノ", 8, "A", "人懐っこくてマシンガントークな妹系少女", "阿澄佳奈", "お裁縫", "ヒューマン", 44, 15, 156, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (6, 101201, 0, 24, "フォレスティエ", "ハツネ", 12, "A", "みんなのために超能力を使う眠り姫", "大橋彩香", "妹と遊ぶこと、二度寝、昼寝、早寝", "エルフ", 46, 17, 156, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！");
