INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (14, 101601, 0, 10, "ルーセント学院", "スズナ", 4, "O", "天真爛漫で人気者のカリスマモデル", "上坂すみれ", "ファッション", "魔族", 48, 17, 167, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！");
