INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (5, 102001, 0, 3, "リトルリリカル", "ミミ", 4, "O", "お歌もにんじんも、ウサギさんも大好き♪", "日高里菜", "かわいいもの集め", "獣人族", 21, 10, 117, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (9, 102101, 0, 9, "サレンディア救護院", "クルミ", 6, "B", "泣き虫で臆病な守ってあげたい女の子", "植田佳奈", "観劇、おままごと", "ヒューマン", 40, 12, 150, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (7, 102201, 0, 22, "悪魔偽王国軍（ディアボロス）", "ヨリ", 11, "O", "人見知りであまのじゃくな女の子", "原紗友里", "ゲーム全般", "魔族", 40, 13, 150, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…");
