INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (9, 102501, 0, 12, "サレンディア救護院", "スズメ", 12, "O", "お嬢さまのためにがんばるドジっ娘メイド", "悠木碧", "ご奉仕", "ヒューマン", 43, 15, 154, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…");
