INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (13, 102701, 0, 30, "トワイライトキャラバン", "エリコ", 7, "B", "運命の相手に一途すぎる乙女", "橋本ちなみ", "実験、裁縫、料理", "魔族", 43, 16, 154, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (9, 102801, 0, 4, "サレンディア救護院", "サレン", 10, "A", "救護院を経営する優しい庶民派お嬢様", "堀江由衣", "経営、お茶会", "エルフ", 43, 17, 156, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (4, 102901, 0, 24, "カルミナ", "ノゾミ", 1, "B", "歌って踊れる大人気アイドル", "日笠陽子", "舞台鑑賞、ダンス", "ヒューマン", 40, 17, 157, "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪");
