INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (7, 103101, 0, 22, "悪魔偽王国軍（ディアボロス）", "シノブ", 12, "AB", "占いが得意な霊能少女", "大坪由佳", "占い", "魔族", 42, 18, 157, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね");
