INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (6, 104001, 0, 6, "フォレスティエ", "アオイ", 6, "AB", "「友達」に憧れる、エルフの森の女の子", "花澤香菜", "友達作りのイメトレ", "エルフ", 44, 13, 158, "友達ができるその日まで…\nBB団で\nトレーニングですっ！");
