INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (15, 104501, 0, 19, "ヴァイスフリューゲル　ランドソル支部", "クウカ", 11, "AB", "妄想大好き！　ほんとは照れ屋な女の子", "長妻樹里", "小説を読むこと", "ヒューマン", 49, 18, 157, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (12, 104601, 0, 1, "メルクリウス財団", "タマキ", 3, "AB", "弱きを助け強きをくじく猫娘", "沼倉愛美", "猫とたわむれること", "獣人族", 48, 19, 158, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪");
