INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (12, 104801, 0, 11, "メルクリウス財団", "ミフユ", 11, "O", "仕事も私事も効率優先な傭兵少女", "田所あずさ", "傭兵などのアルバイト", "ヒューマン", 49, 20, 163, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (3, 104901, 0, 24, "ラビリンス", "シズル", 10, "O", "お姉ちゃんがお世話してあげるからねっ！", "生天目仁美", "家事全般", "ヒューマン", 54, 18, 168, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (14, 105001, 0, 3, "ルーセント学院", "ミサキ", 1, "A", "ちょっとおませな恋に恋する女の子", "久野美咲", "ファッション誌鑑賞、コスメ集め", "魔族", 22, 11, 120, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (13, 105101, 0, 7, "トワイライトキャラバン", "ミツキ", 3, "A", "実験が趣味の危険な科学者", "三石琴乃", "研究、実験", "ヒューマン", 53, 27, 166, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (11, 105201, 0, 14, "牧場（エリザベスパーク）", "リマ", 3, "A", "乙女チックなもふもふアニマル", "徳井青空", "毛繕い、お喋り", "獣人族", 100, 17, 150, "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (15, 105301, 0, 28, "ヴァイスフリューゲル　ランドソル支部", "モニカ", 7, "A", "見た目も中身もお子ちゃまな異国の軍人", "辻あゆみ", "お菓子屋通い", "ヒューマン", 33, 17, 140, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！");
