INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("", 105701, 0, 10, "？？？", "ジータ", 3, "O", "空への冒険を夢見る騎空士の少女", "金元寿子", "冒険、おしゃべり", "ヒューマン", 45, 17, 156, "私ね、一人前の騎空士になりたいんだ\nいつか父さんみたいな騎空士になって、\n空の果てまで旅する。それが私の夢だよ！");
