INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (1, 106001, 0, 2, "美食殿", "キャル", 9, "A", "行き倒れの謎のネコミミ魔法使い", "立花理香", "猫と遊ぶ", "獣人族", 39, 14, 152, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！");
