INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (12, 107901, 0, 1, "メルクリウス財団", "タマキ（サマー）", 3, "AB", "弱きを助け強きをくじく猫娘", "沼倉愛美", "猫とたわむれること", "獣人族", 48, 19, 158, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (12, 108001, 0, 11, "メルクリウス財団", "ミフユ（サマー）", 11, "O", "仕事も私事も効率優先な傭兵少女", "田所あずさ", "傭兵などのアルバイト", "ヒューマン", 49, 20, 163, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (7, 108101, 0, 22, "悪魔偽王国軍（ディアボロス）", "シノブ（ハロウィン）", 12, "AB", "占いが得意な霊能少女", "大坪由佳", "占い", "魔族", 42, 18, 157, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (7, 108201, 0, 23, "悪魔偽王国軍（ディアボロス）", "ミヤコ（ハロウィン）", 1, "B", "プリン大好きゴースト娘", "雨宮天", "プリンを食べること", "魔族", 32, 14, 130, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (14, 108301, 0, 3, "ルーセント学院", "ミサキ（ハロウィン）", 1, "A", "ちょっとおませな恋に恋する女の子", "久野美咲", "ファッション誌鑑賞、コスメ集め", "魔族", 22, 11, 120, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (4, 108401, 0, 3, "カルミナ", "チカ（クリスマス）", 6, "O", "人々を守るために歌う、唱喚士の少女", "福原綾香", "各種楽器", "ヒューマン", 46, 17, 163, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (9, 108501, 0, 9, "サレンディア救護院", "クルミ（クリスマス）", 6, "B", "泣き虫で臆病な守ってあげたい女の子", "植田佳奈", "観劇、おままごと", "ヒューマン", 40, 12, 150, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (9, 108601, 0, 10, "サレンディア救護院", "アヤネ（クリスマス）", 5, "B", "ぷうきちといつも一緒！", "芹澤優", "屋内でできる遊び", "ヒューマン", 38, 14, 148, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (2, 108701, 0, 27, "トゥインクルウィッシュ", "ヒヨリ（ニューイヤー）", 8, "A", "人助けが大好き！　前向き格闘娘", "東山奈央", "人助け、応援", "獣人族", 44, 16, 155, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (2, 108801, 0, 5, "トゥインクルウィッシュ", "ユイ（ニューイヤー）", 4, "O", "戦闘のサポートが得意な、心優しい少女", "種田梨沙", "料理、人間観察", "ヒューマン", 47, 17, 158, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (2, 108901, 0, 12, "トゥインクルウィッシュ", "レイ（ニューイヤー）", 1, "B", "クールで何事にも真っ直ぐな剣士", "早見沙織", "読書、乗馬、お茶", "魔族", 46, 18, 163, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (13, 109001, 0, 30, "トワイライトキャラバン", "エリコ（バレンタイン）", 7, "B", "運命の相手に一途すぎる乙女", "橋本ちなみ", "実験、裁縫、料理", "魔族", 43, 16, 154, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (3, 109101, 0, 24, "ラビリンス", "シズル（バレンタイン）", 10, "O", "お姉ちゃんがお世話してあげるからねっ！", "生天目仁美", "家事全般", "ヒューマン", 54, 18, 168, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("", 109201, 0, 1, "？？？", "アン", 12, "AB", "英霊と契約を結んだマナリアの天才王女", "日笠陽子", "読書", "ヒューマン", 55, 17, 156, "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("", 109301, 0, 4, "？？？", "ルゥ", 2, "O", "マナリア魔法学院の新入生", "こやまきみこ", "食べること、眠ること", "ヒューマン", 45, 16, 144, "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("", 109401, 0, 3, "？？？", "グレア", 11, "B", "人を超越した力を有す心優しい竜姫", "福原綾香", "ピアノ", "半人半竜", 67, 17, 167, "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (15, 109501, 0, 19, "ヴァイスフリューゲル　ランドソル支部", "クウカ（オーエド）", 11, "AB", "妄想大好き！　ほんとは照れ屋な女の子", "長妻樹里", "小説を読むこと", "ヒューマン", 49, 18, 157, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (15, 109601, 0, 31, "ヴァイスフリューゲル　ランドソル支部", "ニノン（オーエド）", 8, "O", "トーゴクの神秘、オシエテクダサイ！", "佐藤聡美", "忍法開発", "ヒューマン", 51, 16, 163, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！");
