INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("", 114701, 0, 11, "？？？", "ムイミ（ニューイヤー）", 8, "O", "さまよえる謎の少女", "潘めぐみ", "冒険、思い出話", "ヒューマン", 40, 16, 148, "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ");
