INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (10, 116001, 0, 22, "自警団（カォン）", "マホ（シンデレラ）", 9, "O", "マホマホ王国のプリンセス", "内田真礼", "空想、ぬいぐるみ集め", "獣人族", 42, 16, 155, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？");
