INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (12, 116801, 0, 1, "メルクリウス財団", "タマキ（作業服）", 3, "AB", "弱きを助け強きをくじく猫娘", "沼倉愛美", "猫とたわむれること", "獣人族", 48, 19, 158, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (12, 116901, 0, 11, "メルクリウス財団", "ミフユ（作業服）", 11, "O", "仕事も私事も効率優先な傭兵少女", "田所あずさ", "傭兵などのアルバイト", "ヒューマン", 49, 20, 163, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから");
