INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (3, 117101, 0, 24, "ラビリンス", "シズル（サマー）", 10, "O", "お姉ちゃんがお世話してあげるからねっ！", "生天目仁美", "家事全般", "ヒューマン", 54, 18, 168, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！");
