INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (13, 117501, 0, 7, "トワイライトキャラバン", "ミツキ（オーエド）", 3, "A", "実験が趣味の危険な科学者", "三石琴乃", "研究、実験", "ヒューマン", 53, 27, 166, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (15, 117601, 0, 10, "ヴァイスフリューゲル　ランドソル支部", "ユキ（オーエド）", 10, "AB", "ボクは誰よりも美しい", "大空直美", "鏡で自分を見ること", "エルフ", 40, 14, 150, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪");
