INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (13, 121901, 0, 5, "トワイライトキャラバン", "アンナ（パイレーツ）", 7, "A", "前世を信じる中二病患者、「疾風の冥姫」", "髙野麻美", "小説執筆", "魔族", 45, 17, 159, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (7, 122001, 0, 22, "悪魔偽王国軍（ディアボロス）", "シノブ（パイレーツ）", 12, "AB", "占いが得意な霊能少女", "大坪由佳", "占い", "魔族", 42, 18, 157, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね");
