INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("", 122301, 0, 6, "？？？", "ヴァンピィ", 12, "AB", "けんぞくのご主人様", "釘宮理恵", "お散歩、お料理", "魔族", 41, "??", 149, "");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (2, 122401, 0, 27, "トゥインクルウィッシュ", "ヒヨリ（サマー）", 8, "A", "人助けが大好き！　前向き格闘娘", "東山奈央", "人助け、応援", "獣人族", 44, 16, 155, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？");
