INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (2, 122601, 0, 5, "トゥインクルウィッシュ", "ユイ（サマー）", 4, "O", "戦闘のサポートが得意な、心優しい少女", "種田梨沙", "料理、人間観察", "ヒューマン", 47, 17, 158, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！");
